12	/// Create a throwaway dual-repo jj fixture for testing.
13	///
14	/// Mirrors the real dual-repo layout created by `vc-x1 init` minus the
15	/// GitHub side and the `~/.claude/projects/` symlink: app repo at
16	/// `<base>/work/`, bot session repo at `<base>/work/.claude/`, and a local
17	/// bare-git remote per repo under `<base>/remote-*.git/`. Both repos carry
18	/// `.vc-config.toml`, `.gitignore`, an initial described commit with
19	/// matching `ochid:` trailers, and a tracked `main` bookmark.
20	///
21	/// The remotes are local bare-git directories inside the fixture — no
22	/// network, no GitHub. See README.md § test-fixture for details.
23	#[derive(Args, Debug)]
24	pub struct TestFixtureArgs {
25	    /// Fixture root directory [default: $TMPDIR/vc-x1-test-<timestamp>]
26	    #[arg(long, value_name = "PATH")]
27	    pub path: Option<PathBuf>,
28	
29	    /// Leave uncommitted changes in @ so finalize --squash has real work
30	    #[arg(long)]
31	    pub with_pending: bool,
32	
33	    /// Seed both repos from template directories.
34	    ///
35	    /// Same format and semantics as `vc-x1 init --use-template`:
36	    /// `CODE[,BOT]`. If `BOT` is omitted, defaults to the sibling directory
37	    /// `<CODE>.claude`. Non-hidden contents are copied recursively; hidden
38	    /// entries are skipped. `README.md` at the root of each target (if
39	    /// present) gets its first line rewritten to `# <repo-name>`, where
40	    /// the code repo is `work` and the bot repo is `work.claude`.
41	    #[arg(long, value_name = "CODE[,BOT]")]
42	    pub use_template: Option<String>,
43	}
