45	/// Remove a test fixture. Refuses anything whose directory name doesn't
46	/// start with `vc-x1-test-`, so it cannot chew up arbitrary paths.
47	#[derive(Args, Debug)]
48	pub struct TestFixtureRmArgs {
49	    /// Fixture root directory to remove
50	    #[arg(value_name = "PATH")]
51	    pub path: PathBuf,
52	}
