82	/// Parse the `--use-template` value into `(code, bot)` template paths.
83	///
84	/// Format: `CODE[,BOT]`. If `BOT` is omitted, the default is the sibling
85	/// directory whose name is `<CODE-basename>.claude` (via
86	/// `Path::with_file_name`, so a trailing slash on `CODE` does not produce
87	/// a different result).
88	pub(crate) fn parse_use_template(
89	    s: &str,
90	) -> Result<(PathBuf, PathBuf), Box<dyn std::error::Error>> {
91	    let mut parts = s.splitn(2, ',');
92	    let code_raw = parts.next().unwrap_or(""); // OK: splitn always yields at least one element
93	    let bot_raw = parts.next();
94	    let code_trim = code_raw.trim();
95	    if code_trim.is_empty() {
96	        return Err("--use-template: code template path is empty".into());
97	    }
98	    let code = PathBuf::from(code_trim);
99	    let bot = match bot_raw.map(str::trim) {
100	        Some(b) if !b.is_empty() => PathBuf::from(b),
101	        _ => {
102	            let file_name = code.file_name().ok_or_else(|| {
103	                format!(
104	                    "--use-template: cannot derive default bot path from '{}' (no file name component)",
105	                    code.display()
106	                )
107	            })?;
108	            let new_name = format!("{}.claude", file_name.to_string_lossy());
109	            code.with_file_name(new_name)
110	        }
111	    };
112	    Ok((code, bot))
113	}
