220	fn jj_chid(rev: &str, cwd: &Path) -> Result<String, Box<dyn std::error::Error>> {
221	    let full = run(
222	        "jj",
223	        &[
224	            "log",
225	            "-r",
226	            rev,
227	            "--no-graph",
228	            "-T",
229	            "change_id",
230	            "--limit",
231	            "1",
232	        ],
233	        cwd,
234	    )?;
235	    Ok(full[..full.len().min(12)].to_string())
236	}
