281	pub fn init(args: &InitArgs) -> Result<(), Box<dyn std::error::Error>> {
282	    debug!("init: enter");
283	    let parent_dir = match &args.dir {
284	        Some(d) => d.clone(),
285	        None => std::env::current_dir()?,
286	    };
287	    let project_dir = parent_dir.join(&args.name);
288	    let session_dir = project_dir.join(".claude");
289	
290	    // Preflight checks
291	    info!("Preflight checks...");
292	
293	    // Check tools
294	    run("gh", &["auth", "status"], Path::new("."))
295	        .map_err(|_| "gh is not installed or not authenticated (run: gh auth login)")?;
296	    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;
297	
298	    let owner = match &args.owner {
299	        Some(o) => o.clone(),
300	        None => gh_whoami()?,
301	    };
302	
303	    if project_dir.exists() {
304	        return Err(format!("'{}' already exists", project_dir.display()).into());
305	    }
306	
307	    let code_repo = format!("{owner}/{}", args.name);
308	    let session_repo = format!("{owner}/{}.claude", args.name);
309	
310	    if gh_repo_exists(&owner, &args.name)? {
311	        return Err(format!("GitHub repo '{code_repo}' already exists").into());
312	    }
313	    if gh_repo_exists(&owner, &format!("{}.claude", args.name))? {
314	        return Err(format!("GitHub repo '{session_repo}' already exists").into());
315	    }
316	
317	    let templates = match &args.use_template {
318	        Some(s) => {
319	            let (code_t, bot_t) = parse_use_template(s)?;
320	            validate_templates(&code_t, &bot_t)?;
321	            Some((code_t, bot_t))
322	        }
323	        None => None,
324	    };
325	
326	    let visibility = if args.private {
327	        "--private"
328	    } else {
329	        "--public"
330	    };
331	
332	    if args.dry_run {
333	        info!("Dry run — would execute:");
334	        info!("  1. Create directories: {}", project_dir.display());
335	        info!("  2. git init + jj git init --colocate on both repos");
336	        info!("  3. Write .vc-config.toml and .gitignore to both");
337	        match &templates {
338	            Some((c, b)) => {
339	                info!(
340	                    "  4. Copy templates (non-hidden) into both repos + rewrite README.md first line"
341	                );
342	                info!("       code: {}", c.display());
343	                info!("       bot:  {}", b.display());
344	            }
345	            None => info!("  4. (skipped — no --use-template)"),
346	        }
347	        info!("  5. jj commit both with placeholder ochids");
348	        info!("  6. Get both chids, jj describe both with correct ochids");
349	        info!("  7. Remove jj from both (git clean -xdf)");
350	        info!("  8. gh repo create {session_repo} {visibility}, push");
351	        info!("  9. gh repo create {code_repo} {visibility}, push");
352	        info!("  10. jj git init --colocate on both repos");
353	        info!("  11. Create Claude Code symlink");
354	        return Ok(());
355	    }
356	
357	    // Step 1: Create directories
358	    info!("Step 1: Creating project directories...");
359	    mkdir_p(&project_dir)?;
360	    mkdir_p(&session_dir)?;
361	
362	    // Step 2: git init + jj init on both repos
363	    info!("Step 2: Initializing repos...");
364	    run("git", &["init"], &project_dir)?;
365	    run("jj", &["git", "init", "--colocate"], &project_dir)?;
366	    run("git", &["init"], &session_dir)?;
367	    run("jj", &["git", "init", "--colocate"], &session_dir)?;
368	
369	    // Step 3: Write config files
370	    info!("Step 3: Writing config files...");
371	    write_file(&project_dir.join(".vc-config.toml"), VC_CONFIG_CODE)?;
372	    write_file(&project_dir.join(".gitignore"), GITIGNORE_CODE)?;
373	    write_file(&session_dir.join(".vc-config.toml"), VC_CONFIG_SESSION)?;
374	    write_file(&session_dir.join(".gitignore"), GITIGNORE_SESSION)?;
375	
376	    // Step 4: Copy templates (if --use-template)
377	    if let Some((code_t, bot_t)) = &templates {
378	        info!("Step 4: Copying templates...");
379	        info!("  code: {} -> {}", code_t.display(), project_dir.display());
380	        copy_template_recursive(code_t, &project_dir)?;
381	        rewrite_readme_first_line(&project_dir, &args.name)?;
382	        info!("  bot:  {} -> {}", bot_t.display(), session_dir.display());
383	        copy_template_recursive(bot_t, &session_dir)?;
384	        let session_name = format!("{}.claude", args.name);
385	        rewrite_readme_first_line(&session_dir, &session_name)?;
386	    }
387	
388	    // Step 5: jj commit both with placeholder ochids
389	    info!("Step 5: Committing both repos with placeholder ochids...");
390	    run(
391	        "jj",
392	        &["commit", "-m", "Initial commit\n\nochid: /none"],
393	        &project_dir,
394	    )?;
395	    run(
396	        "jj",
397	        &["commit", "-m", "Initial commit\n\nochid: /none"],
398	        &session_dir,
399	    )?;
400	
401	    // Step 6: Get both chids, then describe both with correct ochids
402	    info!("Step 6: Setting ochid cross-references...");
403	    let code_chid = jj_chid("@-", &project_dir)?;
404	    let session_chid = jj_chid("@-", &session_dir)?;
405	
406	    let code_desc = format!("Initial commit\n\nochid: /.claude/{session_chid}");
407	    let session_desc = format!("Initial commit\n\nochid: /{code_chid}");
408	    run("jj", &["describe", "@-", "-m", &code_desc], &project_dir)?;
409	    run("jj", &["describe", "@-", "-m", &session_desc], &session_dir)?;
410	
411	    {
412	        let hash = run("git", &["rev-parse", "HEAD"], &project_dir)?;
413	        debug!("code repo: chid={code_chid} hash={hash}");
414	        let hash = run("git", &["rev-parse", "HEAD"], &session_dir)?;
415	        debug!(".claude:   chid={session_chid} hash={hash}");
416	    }
417	
418	    // Step 7: Set bookmarks (creates git branches), then remove jj
419	    // Bookmarks must be set before removing .jj/ so git has a 'main' branch to push
420	    info!("Step 7: Setting bookmarks and removing jj...");
421	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
422	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &session_dir)?;
423	    // Clean .claude first, then code repo with --exclude to preserve .claude/
424	    run("git", &["clean", "-xdf"], &session_dir)?;
425	    run(
426	        "git",
427	        &["clean", "-xdf", "--exclude", ".claude"],
428	        &project_dir,
429	    )?;
430	    // After removing .jj/, git HEAD is detached — reattach to main
431	    run("git", &["checkout", "main"], &session_dir)?;
432	    run("git", &["checkout", "main"], &project_dir)?;
433	
434	    // Step 8: Create .claude GitHub repo and push
435	    let session_url = format!("git@github.com:{session_repo}.git");
436	    info!("Step 8: Creating GitHub repo {session_repo}...");
437	    run(
438	        "gh",
439	        &["repo", "create", &session_repo, visibility],
440	        &project_dir,
441	    )?;
442	    run(
443	        "git",
444	        &["remote", "add", "origin", &session_url],
445	        &session_dir,
446	    )?;
447	    run_retry(
448	        "git",
449	        &["push", "-u", "origin", "main"],
450	        &session_dir,
451	        args.push_retries,
452	        args.push_retry_delay,
453	    )?;
454	
455	    // Step 9: Create code GitHub repo and push
456	    let code_url = format!("git@github.com:{code_repo}.git");
457	    info!("Step 9: Creating GitHub repo {code_repo}...");
458	    run(
459	        "gh",
460	        &["repo", "create", &code_repo, visibility],
461	        &project_dir,
462	    )?;
463	    run("git", &["remote", "add", "origin", &code_url], &project_dir)?;
464	    run_retry(
465	        "git",
466	        &["push", "-u", "origin", "main"],
467	        &project_dir,
468	        args.push_retries,
469	        args.push_retry_delay,
470	    )?;
471	
472	    // Step 10: Re-initialize jj on both repos
473	    info!("Step 10: Re-initializing jj on both repos...");
474	    run(
475	        "jj",
476	        &["--quiet", "git", "init", "--colocate"],
477	        &project_dir,
478	    )?;
479	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
480	    run(
481	        "jj",
482	        &["bookmark", "track", "main", "--remote=origin"],
483	        &project_dir,
484	    )?;
485	    let code_chid_final = jj_chid("@-", &project_dir)?;
486	
487	    run(
488	        "jj",
489	        &["--quiet", "git", "init", "--colocate"],
490	        &session_dir,
491	    )?;
492	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &session_dir)?;
493	    run(
494	        "jj",
495	        &["bookmark", "track", "main", "--remote=origin"],
496	        &session_dir,
497	    )?;
498	    let session_chid_final = jj_chid("@-", &session_dir)?;
499	
500	    // Step 11: Create Claude Code symlink
501	    info!("Step 11: Creating Claude Code symlink...");
502	    let symlink_dir = {
503	        let home =
504	            std::env::var("HOME").map_err(|_| "HOME environment variable not set".to_string())?;
505	        PathBuf::from(home).join(".claude").join("projects")
506	    };
507	
508	    let sl = symlink::SymLink::new(&project_dir, Path::new(".claude"), &symlink_dir)?;
509	    sl.create(false)?;
510	
511	    info!("");
512	    info!("Done! Project created at {}", project_dir.display());
513	    info!("  Code repo:    {code_repo}  (chid={code_chid_final})");
514	    info!("  Session repo: {session_repo}  (chid={session_chid_final})");
515	    info!(
516	        "  Symlink:      {} -> {}",
517	        sl.symlink_path.display(),
518	        sl.abs_target.display()
519	    );
520	
521	    debug!("init: exit");
522	    Ok(())
523	}
