408	/// Expand comma-separated repo paths, default to `["."]`, and run a closure for each.
409	///
410	/// Header style controls output between repos.
411	/// Continues past errors, printing them to stderr, and returns an error if any failed.
412	pub fn for_each_repo<F>(
413	    raw_repos: &[PathBuf],
414	    header: &Header,
415	    mut body: F,
416	) -> Result<(), Box<dyn std::error::Error>>
417	where
418	    F: FnMut(&Workspace, &Arc<ReadonlyRepo>) -> Result<(), Box<dyn std::error::Error>>,
419	{
420	    let repos: Vec<PathBuf> = if raw_repos.is_empty() {
421	        vec![PathBuf::from(".")]
422	    } else {
423	        raw_repos
424	            .iter()
425	            .flat_map(|p| {
426	                p.to_string_lossy()
427	                    .split(',')
428	                    .map(|s| PathBuf::from(s.trim()))
429	                    .collect::<Vec<_>>()
430	            })
431	            .collect()
432	    };
433	    let multi = repos.len() > 1;
434	    let mut first = true;
435	    let mut errors: Vec<String> = Vec::new();
436	
437	    for repo_path in &repos {
438	        if multi {
439	            match header {
440	                Header::Label(deco) => {
441	                    if !first {
442	                        info!("");
443	                    }
444	                    info!(
445	                        "{}",
446	                        bold(&format!("{deco} {} {deco}", repo_path.display()))
447	                    );
448	                }
449	                Header::None => {}
450	            }
451	        }
452	        first = false;
453	
454	        match load_repo(repo_path) {
455	            Ok((workspace, repo)) => {
456	                if let Err(e) = body(&workspace, &repo) {
457	                    error!("({}): {e}", repo_path.display());
458	                    errors.push(format!("{}: {e}", repo_path.display()));
459	                }
460	            }
461	            Err(e) => {
462	                error!("({}): {e}", repo_path.display());
463	                errors.push(format!("{}: {e}", repo_path.display()));
464	            }
465	        }
466	    }
467	
468	    if errors.is_empty() {
469	        Ok(())
470	    } else {
471	        Err(format!("{} repo(s) had errors", errors.len()).into())
472	    }
473	}
