475	pub fn load_repo(
476	    path: &Path,
477	) -> Result<(Workspace, Arc<ReadonlyRepo>), Box<dyn std::error::Error>> {
478	    let config = StackedConfig::with_defaults();
479	    let settings = UserSettings::from_config(config)?;
480	    let store_factories = StoreFactories::default();
481	    let working_copy_factories = default_working_copy_factories();
482	
483	    let workspace = Workspace::load(&settings, path, &store_factories, &working_copy_factories)?;
484	    let repo = workspace.repo_loader().load_at_head().block_on()?;
485	
486	    Ok((workspace, repo))
487	}
