16	use crate::common;
17	
18	/// Parsed file limit: None (suppress), Some(n) (cap at n), or all.
19	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
20	pub enum FileLimit {
21	    /// Don't show changed files section at all.
22	    None,
23	    /// Show up to N files (with first/last split if truncated).
24	    Cap(usize),
25	    /// Show all files.
26	    All,
27	}
28	
29	impl FileLimit {
30	    fn parse(s: &str) -> Result<Self, String> {
31	        match s {
32	            "0" => Ok(FileLimit::None),
33	            "all" => Ok(FileLimit::All),
34	            _ => s
35	                .parse::<usize>()
36	                .map(FileLimit::Cap)
37	                .map_err(|_| format!("invalid file limit '{s}': expected number, 0, or 'all'")),
38	        }
39	    }
40	}
41	
42	#[derive(Args, Debug)]
43	pub struct ShowArgs {
44	    #[command(flatten)]
45	    pub common: common::CommonArgs,
46	
47	    /// Max changed files: number, 0 (none), or 'all'
48	    #[arg(short = 'f', long = "files", default_value = "50")]
49	    pub files: String,
50	}
51	
52	pub fn show(args: &ShowArgs) -> Result<(), Box<dyn std::error::Error>> {
53	    debug!("show: enter");
54	    let file_limit = FileLimit::parse(&args.files)?;
55	    let c = &args.common;
56	
57	    let spec = common::resolve_spec(c.pos_rev.as_deref(), c.pos_count, &c.revision, c.limit, "@");
58	    let hdr = common::resolve_header(&c.label, c.no_label);
59	
60	    common::for_each_repo(&c.repos, &hdr, |workspace, repo| {
61	        let (ids, anchor_index) =
62	            common::collect_ids(workspace, repo, &spec.rev, spec.desc_count, spec.anc_count)?;
63	
64	        let mut first = true;
65	        for (i, commit_id) in ids.iter().enumerate() {
66	            if !first {
67	                info!("────────────────────────────────────────");
68	            }
69	            first = false;
70	
71	            let commit = repo.store().get_commit(commit_id)?;
72	            show_one_commit(&commit, workspace, repo, file_limit, i == anchor_index)?;
73	        }
74	        Ok(())
75	    })?;
76	    debug!("show: exit");
77	    Ok(())
78	}
79	
80	fn show_one_commit(
81	    commit: &Commit,
82	    workspace: &Workspace,
83	    repo: &Arc<ReadonlyRepo>,
84	    file_limit: FileLimit,
85	    is_primary: bool,
86	) -> Result<(), Box<dyn std::error::Error>> {
87	    // Author
88	    let author = commit.author();
89	    info!(
90	        "Author:    {} <{}> ({})",
91	        author.name,
92	        author.email,
93	        format_timestamp(&author.timestamp)
94	    );
95	
96	    // Committer
97	    let committer = commit.committer();
98	    info!(
99	        "Committer: {} <{}> ({})",
100	        committer.name,
101	        committer.email,
102	        format_timestamp(&committer.timestamp)
103	    );
104	
105	    // Ids
106	    let ids_line = common::format_commit_short(commit);
107	    if is_primary {
108	        info!("Ids:       {}", common::bold(&ids_line));
109	    } else {
110	        info!("Ids:       {ids_line}");
111	    }
112	
113	    // Parents
114	    let root_commit_id = repo.store().root_commit_id().clone();
115	    for parent_id in commit.parent_ids() {
116	        if *parent_id == root_commit_id {
117	            continue;
118	        }
119	        let parent = repo.store().get_commit(parent_id)?;
120	        info!("Parent:    {}", common::format_commit_short(&parent));
121	    }
122	
123	    // Children
124	    let children_ids =
125	        common::resolve_revset(workspace, repo, &format!("children({})", commit.id().hex()))?;
126	    for child_id in &children_ids {
127	        if *child_id == root_commit_id {
128	            continue;
129	        }
130	        let child = repo.store().get_commit(child_id)?;
131	        info!("Child:     {}", common::format_commit_short(&child));
132	    }
133	
134	    // Branches
135	    let branches_str = format_branches(commit, workspace, repo)?;
136	    info!("Branches:  {branches_str}");
137	
138	    // Follows
139	    let follows = find_nearest_tag(commit, workspace, repo, true)?;
140	    info!("Follows:   {}", follows.as_deref().unwrap_or("")); // OK: obvious
141	
142	    // Precedes
143	    let precedes = find_nearest_tag(commit, workspace, repo, false)?;
144	    info!("Precedes:  {}", precedes.as_deref().unwrap_or("")); // OK: obvious
145	
146	    // Description (body only — title is on the Ids line)
147	    print_description(commit);
148	
149	    // Changed files
150	    if file_limit != FileLimit::None {
151	        print_diff(commit, repo, file_limit)?;
152	    }
153	
154	    Ok(())
155	}
156	
157	fn find_nearest_tag(
158	    commit: &Commit,
159	    workspace: &Workspace,
160	    repo: &Arc<ReadonlyRepo>,
161	    ancestor: bool,
162	) -> Result<Option<String>, Box<dyn std::error::Error>> {
163	    let commit_hex = commit.id().hex();
164	
165	    let revset_str = if ancestor {
166	        format!("heads(tags() & ::{})", commit_hex)
167	    } else {
168	        format!("roots(tags() & {}::)", commit_hex)
169	    };
170	
171	    let tag_ids = common::resolve_revset(workspace, repo, &revset_str)?;
172	    if tag_ids.is_empty() {
173	        return Ok(None);
174	    }
175	
176	    let tag_id = &tag_ids[0];
177	    let view = repo.view();
178	    for (name, local_remote) in view.tags() {
179	        if local_remote.local_target.added_ids().any(|id| id == tag_id) {
180	            return Ok(Some(name.as_str().to_string()));
181	        }
182	    }
183	
184	    Ok(None)
185	}
186	
187	fn format_branches(
188	    commit: &Commit,
189	    workspace: &Workspace,
190	    repo: &Arc<ReadonlyRepo>,
191	) -> Result<String, Box<dyn std::error::Error>> {
192	    let commit_hex = commit.id().hex();
193	    let view = repo.view();
194	    let mut names: Vec<String> = Vec::new();
195	
196	    for (name, local_remote) in view.bookmarks() {
197	        for bookmark_id in local_remote.local_target.added_ids() {
198	            let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
199	            let results = common::resolve_revset(workspace, repo, &revset_str)?;
200	            if !results.is_empty() {
201	                names.push(name.as_str().to_string());
202	                break;
203	            }
204	        }
205	
206	        for (remote_name, remote_ref) in &local_remote.remote_refs {
207	            if remote_name.as_str() == "git" {
208	                continue;
209	            }
210	            for bookmark_id in remote_ref.target.added_ids() {
211	                let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
212	                let results = common::resolve_revset(workspace, repo, &revset_str)?;
213	                if !results.is_empty() {
214	                    names.push(format!("{}@{}", name.as_str(), remote_name.as_str()));
215	                    break;
216	                }
217	            }
218	        }
219	    }
220	
221	    Ok(names.join(", "))
222	}
223	
224	fn format_timestamp(ts: &jj_lib::backend::Timestamp) -> String {
225	    let millis = ts.timestamp.0;
226	    let secs = millis / 1000;
227	    let tz_minutes = ts.tz_offset;
228	
229	    let dt = chrono::DateTime::from_timestamp(secs, 0)
230	        .unwrap_or_default() // OK: invalid timestamp → epoch for display
231	        .with_timezone(
232	            &chrono::FixedOffset::east_opt(tz_minutes * 60).unwrap_or(chrono::Utc.fix()), // OK: invalid tz → UTC for display
233	        );
234	
235	    dt.format("%Y-%m-%d %H:%M:%S").to_string()
236	}
237	
238	fn print_description(commit: &Commit) {
239	    let desc = commit.description();
240	    let body: String = desc
241	        .lines()
242	        .skip(1)
243	        .skip_while(|l| l.is_empty())
244	        .collect::<Vec<_>>()
245	        .join("\n");
246	
247	    info!("Description:");
248	    for line in body.lines() {
249	        info!("    {line}");
250	    }
251	}
252	
253	fn print_diff(
254	    commit: &Commit,
255	    repo: &Arc<ReadonlyRepo>,
256	    file_limit: FileLimit,
257	) -> Result<(), Box<dyn std::error::Error>> {
258	    let parent_tree = commit.parent_tree(repo.as_ref()).block_on()?;
259	    let commit_tree = commit.tree();
260	
261	    let diff_iter = TreeDiffIterator::new(&parent_tree, &commit_tree, &EverythingMatcher);
262	
263	    let mut lines: Vec<String> = Vec::new();
264	    for entry in diff_iter {
265	        let diff = entry.values?;
266	        let before = diff.before.as_resolved().cloned().flatten();
267	        let after = diff.after.as_resolved().cloned().flatten();
268	
269	        if matches!(&before, Some(TreeValue::Tree(_))) || matches!(&after, Some(TreeValue::Tree(_)))
270	        {
271	            continue;
272	        }
273	
274	        let path_str = entry.path.as_internal_file_string().to_string();
275	
276	        let line = match (before, after) {
277	            (None, Some(value)) => {
278	                format!("    Added {} {path_str}", file_type_str(&value))
279	            }
280	            (Some(_), None) => {
281	                format!(
282	                    "    Removed {} {path_str}",
283	                    file_type_str_from_merged(&diff.before),
284	                )
285	            }
286	            (Some(_), Some(value)) => {
287	                format!("    Modified {} {path_str}", file_type_str(&value))
288	            }
289	            (None, None) => continue,
290	        };
291	        lines.push(line);
292	    }
293	
294	    let total = lines.len();
295	    let cap = match file_limit {
296	        FileLimit::All | FileLimit::None => 0,
297	        FileLimit::Cap(n) => n,
298	    };
299	    let show_all = cap == 0 || total <= cap;
300	
301	    if show_all {
302	        info!("Changed files: {total}");
303	        for line in &lines {
304	            info!("{line}");
305	        }
306	    } else {
307	        info!("Changed files: {total}, showing first {cap}");
308	        for line in &lines[..cap] {
309	            info!("{line}");
310	        }
311	    }
312	
313	    Ok(())
314	}
315	
316	fn file_type_str(value: &TreeValue) -> &'static str {
317	    match value {
318	        TreeValue::File {
319	            executable: false, ..
320	        } => "regular file",
321	        TreeValue::File {
322	            executable: true, ..
323	        } => "executable file",
324	        TreeValue::Symlink(_) => "symlink",
325	        TreeValue::Tree(_) => "tree",
326	        TreeValue::GitSubmodule(_) => "git submodule",
327	    }
328	}
329	
330	fn file_type_str_from_merged(merged: &jj_lib::merge::Merge<Option<TreeValue>>) -> &'static str {
331	    if let Some(Some(value)) = merged.as_resolved() {
332	        file_type_str(value)
333	    } else {
334	        "file"
335	    }
