mod tests {
    use std::path::PathBuf;

    use clap::Parser;

    use crate::{Cli, Commands};

    fn parse(args: &[&str]) -> super::ShowArgs {
        let cli = Cli::try_parse_from(args).unwrap();
        match cli.command {
